function normalizeText(s){return (s||"").toLowerCase().replace(/\s+/g,"");}

function keywordMatches(keyword, query){
  const k=keyword.toLowerCase();
  const q=query.toLowerCase();
  if(!q) return true;
  if(k===q) return true;
  if(q.length>=2 && (k.includes(q)||q.includes(k))) return true;
  return false;
}

function textMatches(text, query){
  const t=text.toLowerCase();
  const q=query.toLowerCase();
  if(!q) return true;
  if(q.length===1){
    let i=t.indexOf(q);
    while(i!==-1){
      const next=t[i+1];
      if(!next||!/[\uac00-\ud7a3]/.test(next)) return true;
      i=t.indexOf(q,i+1);
    }
    return false;
  }
  return t.includes(q);
}

function getAllQuestions(){
  const list=[];
  TOPICS.forEach(t=>{
    t.questions.forEach((item,idx)=>{
      list.push({topicId:t.id,topicName:t.name,topicEmoji:t.emoji,q:item.q,keywords:item.keywords,answer:item.answer,qIndex:idx});
    });
  });
  return list;
}

function findAnswerByQuestion(text){
  const n=normalizeText(text);
  for(const t of TOPICS){
    for(const item of t.questions){
      if(normalizeText(item.q)===n) return item.answer;
    }
  }
  let best=null,bestScore=0;
  const lower=text.toLowerCase();
  for(const t of TOPICS){
    for(const item of t.questions){
      let score=0;
      (item.keywords||[]).forEach(k=>{if(lower.includes(k.toLowerCase()))score+=k.length>=2?2:1;});
      (t.keywords||[]).forEach(k=>{if(lower.includes(k.toLowerCase()))score+=1;});
      if(normalizeText(item.q).includes(n.slice(0,6))&&n.length>=4) score+=3;
      if(score>bestScore){bestScore=score;best=item.answer;}
    }
  }
  return bestScore>=2?best:null;
}

function searchItems(query){
  const q=query.trim().toLowerCase();
  if(!q) return {topics:TOPICS.map(t=>({...t,matchCount:t.questions.length,active:true})),questions:[]};
  const topicResults=TOPICS.map(t=>{
    let matchCount=0;
    const topicMatch=(t.keywords||[]).some(k=>keywordMatches(k,q))||textMatches(t.name,q);
    t.questions.forEach(item=>{
      const hit=(item.keywords||[]).some(k=>keywordMatches(k,q))||textMatches(item.q,q)||topicMatch;
      if(hit) matchCount++;
    });
    return {...t,matchCount,active:topicMatch||matchCount>0};
  });
  const questions=[];
  TOPICS.forEach(t=>{
    t.questions.forEach((item,idx)=>{
      const hit=(item.keywords||[]).some(k=>keywordMatches(k,q))||textMatches(item.q,q)||(t.keywords||[]).some(k=>keywordMatches(k,q));
      if(hit) questions.push({topicId:t.id,topicName:t.name,topicEmoji:t.emoji,q:item.q,answer:item.answer,qIndex:idx});
    });
  });
  return {topics:topicResults,questions};
}

function getTopicById(id){return TOPICS.find(t=>t.id===id);}
